using System.Linq;
using System.Web.Mvc;
using YourNamespace.Models; // Ensure this namespace matches your project

namespace YourNamespace.Controllers
{
    public class ProductController : Controller
    {
        private readonly YourDbContext _context;

        public ProductController()
        {
            _context = new YourDbContext();
        }

        public ActionResult Reviews(int productId)
        {
            var reviews = _context.Reviews
                .Where(r => r.ProductId == productId)
                .Select(r => new ReviewViewModel
                {
                    UserName = r.UserName,
                    Content = r.Content,
                    SubmissionDate = r.SubmissionDate
                })
                .ToList();

            return View(reviews);
        }
    }
}

@model IEnumerable<YourNamespace.Models.ReviewViewModel>

@foreach (var review in Model)
{
    <div class="review">
        <strong>@review.UserName</strong> - <em>@review.SubmissionDate.ToShortDateString()</em>
        <div class="content">
            @Html.Raw(review.Content)
        </div>
    </div>
}